**Input:**

*   A text file (e.g., "text.txt") containing multiple lines of text.
*   A word to search for (e.g., "the").

**Output:**

*   The number of occurrences of the specified word in the text file.

**Example:**

If the text file "text.txt" contains:

```
The quick brown fox jumps over the lazy dog.
The dog is happy.
The end.
```

And the word to search for is "the", the output should be:

```
Number of occurrences of "the": 3
```

**C++ Code:**

```cpp
#include <iostream>
#include <fstream>
#include <string>
#include <vector>

using namespace std;

int main() {
    string filename, wordToSearch;

    cout << "Enter the filename: ";
    cin >> filename;

    cout << "Enter the word to search for: ";
    cin >> wordToSearch;

    ifstream inputFile(filename);

    if (!inputFile.is_open()) {
        cerr << "Error opening file: " << filename << endl;
        return 1;
    }

    vector<string> occurrences;
    string line;

    while (getline(inputFile, line)) {
        size_t pos = 0;
        while ((pos = line.find(wordToSearch, pos)) != string::npos) {
            occurrences.push_back(line.substr(pos, wordToSearch.length()));
            pos += wordToSearch.length();
        }
    }

    inputFile.close();

    cout << "Number of occurrences of \"" << wordToSearch << "\": " << occurrences.size() << endl;

    return 0;
}
```

